t_gene_names = unique(bg_filt_table[, 9:10]) # Perform DE analysis now using the filtered data results_genes = stattest(bg_filt, feature=&quot;gene&quot;, covariate=&quot;condition&quot;, getFC=TRUE, meas=&quot;FPKM&quot;) results_genes = merge(results_genes, bg_filt_gene_names, by.x=c(&quot;id&quot;), by.y=c(&quot;gene_id&quot;)) # Identify the significant genes with p-value &lt; 0.05 sig_genes = subset(results_genes, results_genes$pval&lt;0.05) # Output the significant gene results to a tab delimited file write.table(sig_genes, &quot;HCC1395_Tumor_vs_Normal_gene_results_sig.tsv&quot;, sep=&quot;	&quot;, quote=FALSE, row.names = FALSE) # Exit the R session quit(save=&quot;no&quot;) Practical Exercise 10 - Volcano plot Navigate to previously created folder for DE results and then start an R session cd $RNA_HOME/practice/de/ballgown/ref_only/ R Run the following R commands in your R session. #Load libraries library(ballgown) library(ggplot2) library(ggrepel) #If X11 not available, open a pdf device for output of all plots pdf(file=&quot;practical_exercise_10_volcano.pdf&quot;) #### Import the gene expression data from the practical exercises (HISAT2/StringTie/Ballgown practicals) #Set working directory where results files exist working_dir = &quot;~/workspace/rnaseq/practice/de/ballgown/ref_only&quot; setwd(working_dir) # List the current contents of this directory dir() #Import expression and differential expression results from the HISAT2/StringTie/Ballgown pipeline load(&#39;bg.rda&#39;) # View a summary of the ballgown object bg # Load gene names for lookup later in the tutorial bg_table = texpr(bg, &#39;all&#39;) bg_gene_names = unique(bg_table[, 9:10]) # Calculate the differential expression results including significance results_genes = stattest(bg, feature=&quot;gene&quot;, covariate=&quot;condition&quot;, getFC=TRUE, meas=&quot;FPKM&quot;) results_genes = merge(results_genes,bg_gene_names,by.x=c(&quot;id&quot;),by.y=c(&quot;gene_id&quot;)) results_genes[,&quot;de&quot;] = log2(results_genes[,&quot;fc&quot;]) #### Plot a volcano plot # Create a new diffexpressed column and set all genes to &quot;no change&quot; results_genes$diffexpressed &lt;- &quot;No&quot; # if log2Foldchange &gt; 2 and pvalue &lt; 0.05, set as &quot;Up regulated&quot; results_genes$diffexpressed[results_genes$de &gt; 0.6 &amp; results_genes$pval &lt; 0.05] &lt;- &quot;Up&quot; # if log2Foldchange &lt; -2 and pvalue &lt; 0.05, set as &quot;Down regulated&quot; results_genes$diffexpressed[results_genes$de &lt; -0.6 &amp; results_genes$pval &lt; 0.05] &lt;- &quot;Down&quot; # Create a new gene label column and populate with NA values results_genes$gene_label &lt;- NA # write the gene names of those significantly upregulated/downregulated to a new column results_genes$gene_label[results_genes$diffexpressed != &quot;No&quot;] &lt;- results_genes$gene_name[results_genes$diffexpressed != &quot;No&quot;] ggplot(data=results_genes[results_genes$diffexpressed != &quot;No&quot;,], aes(x=de, y=-log10(pval), label=gene_label, color = diffexpressed)) + xlab(&quot;log2Foldchange&quot;) + scale_color_manual(name = &quot;Differentially expressed&quot;, values=c(&quot;blue&quot;, &quot;red&quot;)) + geom_point() + theme_minimal() + geom_text_repel() + geom_vline(xintercept=c(-0.6, 0.6), col=&quot;red&quot;) + geom_hline(yintercept=-log10(0.05), col=&quot;red&quot;) + guides(colour = guide_legend(override.aes = list(size=5))) + geom_point(data = results_genes[results_genes$diffexpressed == &quot;No&quot;,], aes(x=de, y=-log10(pval)), colour = &quot;black&quot;) dev.off() quit(save=&quot;no&quot;) To view your plot, go to the following url in your browser: http://YOUR_IP_ADDRESS/workspace/rnaseq/practice/de/ballgown/ref_only/practical_exercise_10_volcano.pdf Note, you must replace YOUR_IP_ADDRESS with your own amazon instance IP or DNS
